#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Enemy {
private:
    std::string name;
    int health;

public:
    Enemy(std::string n, int h) : name(n), health(h) {
        std::cout << "Enemy " << name << " created!" << std::endl;
    }

    ~Enemy() {
        std::cout << "Enemy " << name << " destroyed!" << std::endl;
    }

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }

    void takeDamage(int damage) {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (HP: " << health << ")" << std::endl;
    }
};

// Function that takes ownership
void processEnemy(std::unique_ptr<Enemy> enemy) {
    std::cout << "Processing enemy..." << std::endl;
    enemy->display();
    // enemy is automatically deleted when function ends
}

int main() {
    std::cout << "=== unique_ptr — Exclusive Ownership ===" << std::endl;

    // 1. Creating a unique_ptr
    std::cout << "\n--- Creating unique_ptr ---" << std::endl;
    std::unique_ptr<Enemy> goblin = std::make_unique<Enemy>("Goblin", 30);
    goblin->display();

    // 2. Accessing like a raw pointer
    std::cout << "\n--- Accessing ---" << std::endl;
    goblin->takeDamage(10);

    // 3. Moving ownership (can't copy!)
    std::cout << "\n--- Moving ownership ---" << std::endl;
    std::unique_ptr<Enemy> orc = std::move(goblin);
    // goblin is now empty (nullptr)

    if (goblin == nullptr) {
        std::cout << "goblin is now empty" << std::endl;
    }

    orc->display();

    // 4. Passing to a function (move)
    std::cout << "\n--- Passing ownership ---" << std::endl;
    std::unique_ptr<Enemy> skeleton = std::make_unique<Enemy>("Skeleton", 25);
    processEnemy(std::move(skeleton));
    // skeleton is now empty

    // 5. Vector of unique_ptr
    std::cout << "\n--- Vector of unique_ptr ---" << std::endl;
    std::vector<std::unique_ptr<Enemy>> enemies;
    enemies.push_back(std::make_unique<Enemy>("Goblin", 30));
    enemies.push_back(std::make_unique<Enemy>("Orc", 50));
    enemies.push_back(std::make_unique<Enemy>("Dragon", 100));

    for (const auto& e : enemies) {
        e->display();
    }

    // 6. Release (give up ownership)
    std::cout << "\n--- Releasing ownership ---" << std::endl;
    std::unique_ptr<Enemy> boss = std::make_unique<Enemy>("Boss", 200);
    Enemy* rawPtr = boss.release();  // Release ownership (don't delete automatically)
    rawPtr->display();
    delete rawPtr;  // Must manually delete!

    std::cout << "\n--- unique_ptr advantages ---" << std::endl;
    std::cout << "• Automatically deletes when out of scope" << std::endl;
    std::cout << "• Cannot be copied (exclusive ownership)" << std::endl;
    std::cout << "• No memory leaks" << std::endl;
    std::cout << "• Use std::move to transfer ownership" << std::endl;

    return 0;
}

