#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Weapon {
private:
    std::string name;
    int damage;

public:
    Weapon(std::string n, int d) : name(n), damage(d) {
        std::cout << "Weapon " << name << " created!" << std::endl;
    }

    ~Weapon() {
        std::cout << "Weapon " << name << " destroyed!" << std::endl;
    }

    void display() const {
        std::cout << name << " (Damage: " << damage << ")" << std::endl;
    }
};

int main() {
    auto sword = std::make_unique<Weapon>("Sword", 15);
    sword->display();

    auto moved = std::move(sword);
    if (sword == nullptr) {
        std::cout << "sword is now null (ownership moved)" << std::endl;
    }
    moved->display();

    std::vector<std::unique_ptr<Weapon>> weapons;
    weapons.push_back(std::make_unique<Weapon>("Axe", 20));
    weapons.push_back(std::make_unique<Weapon>("Bow", 12));
    weapons.push_back(std::make_unique<Weapon>("Staff", 18));

    std::cout << "\n=== Weapons in vector ===" << std::endl;
    for (const auto& w : weapons) {
        w->display();
    }

    return 0;
}
